// 1. Get the array of objects from the previous node
const entityMap = $("map").first().json.entity_map;
const newFlows = $('new workflows').first().json.data;

// 2. Create a reverse lookup dictionary: orig_id -> new_id
// This makes swapping the IDs instantly fast and ignores the names entirely
const reverseIdMap = {};
for (const entityName in entityMap) {
  const ids = entityMap[entityName];
  if (ids.orig_id && ids.new_id) {
    // Force strings just in case n8n handles the IDs as numbers
    reverseIdMap[ids.orig_id.toString()] = ids.new_id.toString();
  }
}

// 3. Define the specific nodes we want to target
const targetNodeTypes = [
  'n8n-nodes-base.executeWorkflow',
  'n8n-nodes-base.dataTable'
];

// 4. Helper Function: Recursively search parameters and swap IDs
// This ensures we catch the ID even if n8n nests it inside an "options" object
function replaceOldIds(parameters, idMap) {
  for (const key in parameters) {
    if (typeof parameters[key] === 'object' && parameters[key] !== null) {
      replaceOldIds(parameters[key], idMap);
    } else if (typeof parameters[key] === 'string' || typeof parameters[key] === 'number') {
      const currentValue = parameters[key].toString();
      // If the current parameter value is an old ID in our map, swap it!
      if (idMap[currentValue]) {
        parameters[key] = idMap[currentValue]; 
      }
    }
  }
}

// 5. Loop through the workflows and apply the updates
var jsonFlows = [];
newFlows.forEach(flow => {
  // Ensure the flow actually has a nodes array
  if (flow.nodes && Array.isArray(flow.nodes)) {

    flow.nodes.forEach(node => {
      // If the node type matches our targets, scan its parameters
      if (targetNodeTypes.includes(node.type) && node.parameters) {
        replaceOldIds(node.parameters, reverseIdMap);
      }
    });

  }

  const flow_json = {...flow};

    // 2. THE FIX: Clean the payload for the strict API schema
  // Reset settings to an empty object to clear out unrecognized legacy properties
  flow_json.settings = {};

  // Delete read-only properties that the API will reject on a PUT request
  delete flow_json.id;
  delete flow_json.createdAt;
  delete flow_json.updatedAt;
  delete flow_json.versionId;
  delete flow_json.active; // (Optional: safely prevents accidentally activating half-migrated flows)

    jsonFlows.push({
      id: flow.id,
      workflow: JSON.stringify(flow_json)
    })
});


// 6. Output the updated workflows
// Returning it as 'updatedFlows' attached to the JSON
return jsonFlows;
